import React, { useState, useRef, useEffect } from "react";
import axios from "axios";

const QUICK_QUESTIONS = [
  { id: 1, text: "How to book an appointment?" },
  { id: 2, text: "How to make a payment?" },
  { id: 3, text: "How does doctor approve appointment?" },
  { id: 4, text: "How to reject an appointment?" },
  { id: 5, text: "How does payment work for doctors?" },
  { id: 6, text: "How to contact admin?" },
];

export default function Chatbot() {
  const [isOpen, setIsOpen] = useState(false);
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([
    {
      sender: "bot",
      text: "Hi! I'm your medical assistant 👋 Click a question below or type your own!",
    },
  ]);
  const [loading, setLoading] = useState(false);
  const chatEndRef = useRef(null);
  const token = localStorage.getItem("token");

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat, isOpen]);

  const sendMessage = async (text) => {
    const userText = text || message.trim();
    if (!userText || loading) return;

    setMessage("");
    setChat((prev) => [...prev, { sender: "user", text: userText }]);
    setLoading(true);

    try {
      const res = await axios.post(
        "http://localhost:5000/api/chatbot",
        { message: userText },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setChat((prev) => [...prev, { sender: "bot", text: res.data.reply }]);
    } catch (err) {
      setChat((prev) => [
        ...prev,
        { sender: "bot", text: "Sorry, I'm having trouble. Please try again." },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") sendMessage();
  };

  const showQuickQuestions = chat.length <= 1;

  return (
    <div className="fixed bottom-5 right-5 z-50">
      {isOpen && (
        <div
          style={{
            width: "340px",
            height: "480px",
            display: "flex",
            flexDirection: "column",
            background: "#fff",
            borderRadius: "16px",
            boxShadow: "0 8px 32px rgba(0,0,0,0.18)",
            marginBottom: "12px",
            overflow: "hidden",
          }}
        >
          {/* Header */}
          <div
            style={{
              background: "linear-gradient(135deg, #2563eb, #1d4ed8)",
              padding: "14px 16px",
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
              <div
                style={{
                  width: "36px",
                  height: "36px",
                  borderRadius: "50%",
                  background: "rgba(255,255,255,0.2)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: "18px",
                }}
              >
                🏥
              </div>
              <div>
                <div
                  style={{ color: "#fff", fontWeight: "700", fontSize: "14px" }}
                >
                  Medical Assistant
                </div>
                <div style={{ color: "#bfdbfe", fontSize: "11px" }}>
                  ● Online
                </div>
              </div>
            </div>
            <button
              onClick={() => setIsOpen(false)}
              style={{
                background: "rgba(255,255,255,0.15)",
                border: "none",
                color: "#fff",
                borderRadius: "50%",
                width: "28px",
                height: "28px",
                cursor: "pointer",
                fontSize: "16px",
              }}
            >
              ✕
            </button>
          </div>

          {/* Messages */}
          <div
            style={{
              flex: 1,
              overflowY: "auto",
              padding: "12px",
              background: "#f8fafc",
              display: "flex",
              flexDirection: "column",
              gap: "8px",
            }}
          >
            {chat.map((c, idx) => (
              <div
                key={idx}
                style={{
                  display: "flex",
                  justifyContent:
                    c.sender === "user" ? "flex-end" : "flex-start",
                }}
              >
                <div
                  style={{
                    maxWidth: "80%",
                    padding: "9px 13px",
                    borderRadius:
                      c.sender === "user"
                        ? "16px 16px 4px 16px"
                        : "16px 16px 16px 4px",
                    background:
                      c.sender === "user"
                        ? "linear-gradient(135deg, #2563eb, #1d4ed8)"
                        : "#fff",
                    color: c.sender === "user" ? "#fff" : "#1e293b",
                    fontSize: "13px",
                    lineHeight: "1.5",
                    boxShadow: "0 1px 4px rgba(0,0,0,0.08)",
                  }}
                >
                  {c.text}
                </div>
              </div>
            ))}

            {/* Quick Questions */}
            {showQuickQuestions && (
              <div style={{ marginTop: "4px" }}>
                <div
                  style={{
                    fontSize: "11px",
                    color: "#94a3b8",
                    marginBottom: "8px",
                    textAlign: "center",
                  }}
                >
                  Quick Questions
                </div>
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "6px",
                  }}
                >
                  {QUICK_QUESTIONS.map((q) => (
                    <button
                      key={q.id}
                      onClick={() => sendMessage(q.text)}
                      style={{
                        background: "#fff",
                        border: "1.5px solid #bfdbfe",
                        borderRadius: "10px",
                        padding: "8px 12px",
                        fontSize: "12px",
                        color: "#2563eb",
                        cursor: "pointer",
                        textAlign: "left",
                      }}
                      onMouseEnter={(e) => {
                        e.target.style.background = "#eff6ff";
                        e.target.style.borderColor = "#2563eb";
                      }}
                      onMouseLeave={(e) => {
                        e.target.style.background = "#fff";
                        e.target.style.borderColor = "#bfdbfe";
                      }}
                    >
                      💬 {q.text}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {loading && (
              <div style={{ display: "flex", justifyContent: "flex-start" }}>
                <div
                  style={{
                    background: "#fff",
                    borderRadius: "16px",
                    padding: "10px 14px",
                    boxShadow: "0 1px 4px rgba(0,0,0,0.08)",
                    fontSize: "16px",
                  }}
                >
                  ⏳
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input */}
          <div
            style={{
              padding: "10px 12px",
              background: "#fff",
              borderTop: "1px solid #e2e8f0",
              display: "flex",
              gap: "8px",
            }}
          >
            <input
              type="text"
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Type a message..."
              style={{
                flex: 1,
                border: "1.5px solid #e2e8f0",
                borderRadius: "10px",
                padding: "8px 12px",
                fontSize: "13px",
                outline: "none",
              }}
              onFocus={(e) => (e.target.style.borderColor = "#2563eb")}
              onBlur={(e) => (e.target.style.borderColor = "#e2e8f0")}
            />
            <button
              onClick={() => sendMessage()}
              disabled={loading}
              style={{
                background: loading
                  ? "#94a3b8"
                  : "linear-gradient(135deg, #2563eb, #1d4ed8)",
                border: "none",
                borderRadius: "10px",
                padding: "8px 14px",
                color: "#fff",
                cursor: loading ? "not-allowed" : "pointer",
                fontSize: "16px",
              }}
            >
              ➤
            </button>
          </div>
        </div>
      )}

      {/* Toggle Button */}
      <div style={{ display: "flex", justifyContent: "flex-end" }}>
        <button
          onClick={() => setIsOpen(!isOpen)}
          style={{
            width: "56px",
            height: "56px",
            borderRadius: "50%",
            background: "linear-gradient(135deg, #2563eb, #1d4ed8)",
            border: "none",
            cursor: "pointer",
            fontSize: "24px",
            boxShadow: "0 4px 16px rgba(37,99,235,0.4)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          {isOpen ? "✕" : "💬"}
        </button>
      </div>
    </div>
  );
}
